parameters.jsCode:
const batchSize = 10;

const root = $input.first()?.json ?? {};
const body = root.body ?? {};

const style_type = body.style_type ?? root.style_type ?? null;
const style_keywords = body.style_keywords ?? root.style_keywords ?? [];
const banned = body.banned ?? root.banned ?? [];

function textValue(v) {
  if (v == null) return '';
  if (Array.isArray(v)) {
    const first = v[0];
    if (typeof first === 'string') return first;
    if (first && typeof first === 'object') return String(first.text ?? first.value ?? first.url ?? '');
  }
  if (typeof v === 'object') return String(v.text ?? v.value ?? v.url ?? '');
  return String(v);
}

const fromCards = Array.isArray(body.cards)
  ? body.cards.map((card) => ({
      record_id: card.record_id,
      created_at: card.created_at ?? null,
      content: textValue(card.content),
      card_type: card.card_type ?? '其他',
      tags: Array.isArray(card.tags) ? card.tags : [],
      status: card.status ?? '生效',
      risk: card.risk ?? '低',
    }))
  : [];

const fromItemsRaw = Array.isArray(body?.data?.items) ? body.data.items : [];
const fromItems = fromItemsRaw.map((rec) => {
  const f = rec.fields ?? {};
  return {
    record_id: rec.record_id,
    created_at: textValue(f['创建时间']) || null,
    content: textValue(f['卡片内容']),
    card_type: textValue(f['卡片类型']) || '其他',
    tags: Array.isArray(f['标签']) ? f['标签'] : [],
    status: textValue(f['生效状态']) || '生效',
    risk: textValue(f['风险等级']) || '低',
  };
});

const list = [...fromCards, ...fromItems].filter((x) => x.record_id && x.content);

if (!list.length) {
  return [{
    json: {
      batch_index: 0,
      batch_cards: [],
      warning: 'cards / body.data.items 为空，无法提炼风格',
      debug_keys: Object.keys(root),
    },
  }];
}

const out = [];
for (let i = 0; i < list.length; i += batchSize) {
  out.push({
    json: {
      batch_index: out.length,
      batch_cards: list.slice(i, i + batchSize),
      style_type,
      style_keywords,
      banned,
      total_cards: list.length,
    },
  });
}

return out;

