parameters.jsCode:
/**
 * 合并原卡片 + 打分结果（record_id 对齐）+ 按类型配比筛选风格样本（只输出 content/score/card_type）
 * ✅ 运行模式：Run Once for All Items
 * ✅ 输出：samples[{content, score, card_type}] + samples_count + debug
 *
 * 兼容：
 * - batch_cards 批次输入（任意上游命名）
 * - score 结果 carrier：results / data.results / output(results|data.results) / output为JSON字符串/数组字符串
 * - card_type 统一：价值 -> Value
 */

const items = $input.all().map(i => i.json ?? {});

// ---------- helpers ----------
function stripCodeFence(s) {
  if (!s || typeof s !== 'string') return '';
  return s
    .replace(/^\s*```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
}

function safeJsonParse(s) {
  try { return JSON.parse(s); } catch (e) { return null; }
}

/**
 * 从任意 carrier 抽 results 数组
 */
function extractResultsFromCarrier(carrier) {
  const raw = carrier?.output ?? carrier;

  // 1) 直接结构化 results
  if (Array.isArray(raw?.results)) return raw.results;
  if (Array.isArray(raw?.data?.results)) return raw.data.results;

  // 2) output 里再套一层
  if (Array.isArray(raw?.output?.results)) return raw.output.results;
  if (Array.isArray(raw?.output?.data?.results)) return raw.output.data.results;

  // 3) output 是字符串（常见：```json ... ``` 或 "{...}" 或 "[...]"）
  const maybeStr =
    typeof raw?.output === 'string' ? raw.output :
    typeof raw === 'string' ? raw :
    null;

  if (maybeStr) {
    const txt = stripCodeFence(maybeStr);
    const parsed = safeJsonParse(txt);
    if (Array.isArray(parsed)) return parsed;
    if (Array.isArray(parsed?.results)) return parsed.results;
    if (Array.isArray(parsed?.data?.results)) return parsed.data.results;
  }

  // 4) 有些节点直接把 results 放在顶层 carrier.results
  if (Array.isArray(carrier?.results)) return carrier.results;

  return [];
}

function normType(t) {
  if (!t) return '其他';
  const s = String(t).trim();
  if (!s) return '其他';
  if (s === '价值') return 'Value';
  return s;
}

function toScore(v) {
  const n = typeof v === 'number' ? v : Number(v);
  return Number.isFinite(n) ? n : null;
}

function clampLenText(s, maxLen = 3000) {
  if (s == null) return '';
  const t = String(s);
  return t.length > maxLen ? t.slice(0, maxLen) : t;
}

// ---------- 1) 找 batches（含 batch_cards） ----------
const batches = items.filter(x => Array.isArray(x.batch_cards));

// 如果上游不是 batch_cards，也可能已经是卡片数组，做个兜底：
// 例如某节点直接输出 cards:[...] 或 merged_all:[...]
function fallbackCardsFromItems(all) {
  for (const it of all) {
    if (Array.isArray(it.cards)) return it.cards;
    if (Array.isArray(it.merged_all)) return it.merged_all;
    if (Array.isArray(it.scored_all)) return it.scored_all;
  }
  return null;
}
const fallbackCards = fallbackCardsFromItems(items);

// ---------- 2) 找 score carriers ----------
const scoreCarriers = items.filter(x => extractResultsFromCarrier(x).length > 0);

// ---------- 3) 抽出所有 score rows ----------
const scoreRows = [];
for (const it of scoreCarriers) {
  const batchIndex =
    it?.batch_index ??
    it?.output?.batch_index ??
    it?.output?.data?.batch_index ??
    null;

  const results = extractResultsFromCarrier(it);
  for (const r of results) {
    const rid = r?.record_id ?? r?.recordId;
    if (!rid) continue;
    const score = toScore(r?.score);
    if (score == null) continue;
    scoreRows.push({
      record_id: String(rid),
      score,
      scored_batch_index: batchIndex,
    });
  }
}

// ---------- 4) record_id -> score（同一个record多次出现，取最高分） ----------
const scoreMap = new Map();
for (const r of scoreRows) {
  const prev = scoreMap.get(r.record_id);
  if (prev == null || r.score > prev) scoreMap.set(r.record_id, r.score);
}

// ---------- 5) 合并：给每张卡补 score ----------
const merged = [];

// 优先用 batches.batch_cards
if (batches.length) {
  for (const b of batches) {
    const cards = Array.isArray(b.batch_cards) ? b.batch_cards : [];
    for (const c of cards) {
      const rid = c?.record_id ?? c?.recordId;
      if (!rid) continue;
      const score = scoreMap.has(String(rid)) ? scoreMap.get(String(rid)) : null;
      merged.push({
        record_id: String(rid),
        content: clampLenText(c?.content ?? ''),
        card_type: normType(c?.card_type ?? c?.cardType ?? ''),
        score,
      });
    }
  }
} else if (Array.isArray(fallbackCards)) {
  // 兜底：如果没有 batch_cards，就尝试从 cards/merged_all/scored_all 读
  for (const c of fallbackCards) {
    const rid = c?.record_id ?? c?.recordId;
    if (!rid) continue;
    const score = scoreMap.has(String(rid)) ? scoreMap.get(String(rid)) : toScore(c?.score);
    merged.push({
      record_id: String(rid),
      content: clampLenText(c?.content ?? ''),
      card_type: normType(c?.card_type ?? c?.cardType ?? ''),
      score,
    });
  }
}

// ---------- 6) 筛选池（基础质量） ----------
const THRESHOLD = 70;     // 可调：80 更严，60 更松
const MAX_STYLE = 24;     // 可调：12-30
const EXCLUDE_TYPES = new Set(['CTA']);

function okItem(x) {
  if (!x?.content || !x.content.trim()) return false;
  if (EXCLUDE_TYPES.has(x.card_type)) return false;
  if (typeof x.score !== 'number' || !Number.isFinite(x.score)) return false;
  if (x.score < THRESHOLD) return false;

  // 长度筛选：金句/口播片段一般不宜过长
  const len = x.content.trim().length;
  if (len < 15) return false;
  if (len > 220) return false;

  return true;
}

const pool = merged
  .filter(okItem)
  .map(x => ({ ...x, card_type: normType(x.card_type) }))
  .sort((a, b) => b.score - a.score);

// ---------- 7) 类型配比抽样 + 去重（避免全是金句导致风格贫瘠） ----------
const quota = [
  ['金句', 8],
  ['Value', 6],
  ['Hook', 4],
  ['案例', 3],
  ['术语', 2],
  ['其他', 1],
];

// 去重：完全一致 + 近似（粗暴版：归一化后前80字）
function normKey(content) {
  return content
    .trim()
    .replace(/\s+/g, '')      // 去空白
    .replace(/[“”"']/g, '')   // 去引号
    .slice(0, 80);
}

const picked = [];
const used = new Set();

function countType(type) {
  return picked.reduce((n, it) => n + (it.card_type === type ? 1 : 0), 0);
}

function pickByType(type, n) {
  for (const x of pool) {
    if (picked.length >= MAX_STYLE) break;
    if (countType(type) >= n) break;
    if (x.card_type !== type) continue;

    const key = normKey(x.content);
    if (used.has(key)) continue;

    used.add(key);
    picked.push(x);
  }
}

// 先按配额拿
for (const [t, n] of quota) pickByType(t, n);

// 再补齐：优先补缺口类型（Hook/案例优先），最后再按高分补
const priorityTypes = ['Hook', '案例', 'Value', '金句', '术语', '其他'];
for (const t of priorityTypes) {
  if (picked.length >= MAX_STYLE) break;
  // 如果某类型明显不足，继续补一些
  pickByType(t, Math.min(MAX_STYLE, countType(t) + 2));
}

// 还不够就纯高分补
for (const x of pool) {
  if (picked.length >= MAX_STYLE) break;
  const key = normKey(x.content);
  if (used.has(key)) continue;
  used.add(key);
  picked.push(x);
}

// ✅ 最终只输出 content / score / card_type
const samples = picked.slice(0, MAX_STYLE).map(x => ({
  content: x.content,
  score: x.score,
  card_type: x.card_type,
}));

// 统计每种类型数量（方便你看是不是又全变金句了）
const typeStats = {};
for (const s of samples) {
  typeStats[s.card_type] = (typeStats[s.card_type] || 0) + 1;
}

return [{
  json: {
    samples,
    samples_count: samples.length,
    debug: {
      input_items: items.length,
      batches_count: batches.length,
      score_carriers_count: scoreCarriers.length,
      score_rows_count: scoreRows.length,
      merged_count: merged.length,
      pool_count: pool.length,
      threshold: THRESHOLD,
      max_style: MAX_STYLE,
      type_stats: typeStats,
      warn_if_overfit:
        (typeStats['金句'] || 0) / Math.max(1, samples.length) > 0.7
          ? '样本里“金句”占比>70%，风格会贫瘠：建议在上游补Hook/案例/实操类样本或降低Hook/案例阈值'
          : '',
    }
  }
}];

options.systemMessage:
=你是“文章写法风格 Playbook 提炼器”。你只根据“写法/结构/节奏/排版/措辞习惯”提炼规则，不根据主题内容做判断。

输入：article_samples[]，每条包含：
- content: 文章片段或整段
- type: 卡片类型（可选）
- tags: 标签（可选）

目标：
1) 提炼可复用、可执行、可检查的“文章写法风格规则”，用于后续自动写同风格图文长文。
2) 输出必须是【严格 JSON】（不要 markdown、不要代码块、不要解释性废话）。
3) 规则必须“可落地”：用“必须/禁止/上限/下限/当…就…”表达；尽量量化。

硬规则：
- 只输出 JSON，且必须能被 JSON.parse 解析。
- 不要泄露或重复输入里的敏感信息（例如 api_key、app_secret 等）。
- 若样本不足（太短/同质化），必须在 domain_inference.gaps 写清楚缺口，并在 domain_inference.adaptation_strategy 给出补样本建议。
- 必须区分：文章首屏规则、段落节奏规则、小标题规则、列表/重点框规则、结尾 CTA 规则。
- 必须输出可填空模板（templates），否则后续无法复用。

输出 JSON schema（字段名固定，不可增删）：
