parameters.jsCode:
/**
 * 清洗“风格提炼”输出：把字符串 output 解析为真正 JSON 对象
 * + 额外输出：样本缺失点 / 改进方向 等，便于回调后端
 */

const items = $input.all();

// ------- helpers -------
function stripCodeFence(s) {
  return String(s ?? '')
    .trim()
    .replace(/^\s*```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
}

function tryParse(s) {
  try { return JSON.parse(s); } catch (e) { return null; }
}

function deepParseJsonString(maybe) {
  let obj = tryParse(maybe);
  if (obj && typeof obj === 'object') return obj;

  let raw = stripCodeFence(maybe);

  if (
    (raw.startsWith('"') && raw.endsWith('"')) ||
    (raw.startsWith("'") && raw.endsWith("'"))
  ) raw = raw.slice(1, -1);

  const unescaped = raw
    .replace(/\\n/g, '\n')
    .replace(/\\t/g, '\t')
    .replace(/\\r/g, '\r')
    .replace(/\\"/g, '"')
    .replace(/\\'/g, "'")
    .trim();

  obj = tryParse(unescaped);
  if (obj && typeof obj === 'object') return obj;

  const maybeStrObj = tryParse(`"${unescaped.replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"`);
  if (typeof maybeStrObj === 'string') {
    const again = tryParse(maybeStrObj);
    if (again && typeof again === 'object') return again;
  }

  const m1 = unescaped.match(/\{[\s\S]*\}/);
  const m2 = unescaped.match(/\[[\s\S]*\]/);
  const candidate = (m1 && m1[0]) || (m2 && m2[0]) || '';
  if (candidate) {
    const picked = tryParse(candidate);
    if (picked && typeof picked === 'object') return picked;
  }

  return null;
}

function pickRawFromItem(j) {
  const candidates = [
    j?.output,
    j?.text,
    j?.raw_output,
    j?.raw,
    j?.style,
    j?.style_json_string,
    j?.['风格规则json'],
    j?.['风格规则JSON'],
    j?.['风格规则'],
  ];

  for (const c of candidates) {
    if (typeof c === 'string' && c.trim()) return c;
    if (c && typeof c === 'object') return JSON.stringify(c);
  }
  return JSON.stringify(j ?? {});
}

function toText(v) {
  if (v == null) return '';
  if (Array.isArray(v)) return v.map(x => String(x)).filter(Boolean).join('、');
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}

// ------- main -------
const out = items.map((it, idx) => {
  const j = it.json ?? {};
  const raw0 = pickRawFromItem(j);
  const raw = stripCodeFence(raw0);

  const parsed = deepParseJsonString(raw);

  if (!parsed || typeof parsed !== 'object') {
    throw new Error(
      `第 ${idx + 1} 条风格提炼 output 无法解析为 JSON。raw(前800)：` + raw.slice(0, 800)
    );
  }

  const style_json = Array.isArray(parsed) ? (parsed[0] ?? {}) : parsed;

  // ✅ 抽取“样本缺失点 / 改进方向”（从 domain_inference）
  const di = style_json.domain_inference ?? {};
  const sample_gaps = toText(di.gaps);
  const sample_improvement = toText(di.adaptation_strategy);

  // ✅ 可选：顺手把“主题/偏科”也拆出来（做前端分析面板很有用）
  const sample_topics_arr = Array.isArray(di.topics) ? di.topics : [];
  const sample_topics = sample_topics_arr.join('、');

  const dominant_card_types_arr = Array.isArray(di.dominant_card_types) ? di.dominant_card_types : [];
  const sample_dominant_card_types = dominant_card_types_arr.join('、');

  return {
    json: {
      ...j, // ✅ 保留上游全部字段
      style_json,
      style_json_string: JSON.stringify(style_json, null, 2),
      raw_output: raw,

      // ✅ 新增：回调后端用（字段名可按需调整）
      sample_gaps,                 // 样本缺失点（文本）
      sample_improvement,          // 改进方向（文本）
      sample_topics,               // 主题标签（文本）
      sample_topics_arr,           // 主题标签（数组）
      sample_dominant_card_types,  // 偏科类型（文本）
      dominant_card_types_arr,     // 偏科类型（数组）
    },
  };
});

return out;

const input = $input.first()?.json ?? {};
const body = $('Webhook').first()?.json?.body ?? {};

const styleId =
  input.style_id ||
  input.record_id ||
  input.style_record_id ||
  body.style_id ||
  body.task_id ||
  body.record_id ||
  body.style_record_id ||
  '';

if (!styleId) {
  throw new Error('style_id 缺失，无法回调后端');
}

let style = input.style_json;
if (!style || typeof style !== 'object') {
  const raw = input.style_json_string || input.output || '';
  if (typeof raw === 'string' && raw.trim()) {
    const cleaned = raw
      .trim()
      .replace(/^\s*```(?:json)?\s*/i, '')
      .replace(/\s*```\s*$/i, '')
      .trim();
    style = JSON.parse(cleaned);
  }
}

if (!style || typeof style !== 'object') {
  throw new Error('缺少 style_json，无法回调后端');
}

const di = style.domain_inference ?? {};
const sampleGaps =
  (typeof input.sample_gaps === 'string' && input.sample_gaps.trim())
    ? input.sample_gaps.trim()
    : (di.gaps != null ? String(di.gaps).trim() : '');
const sampleImprovement =
  (typeof input.sample_improvement === 'string' && input.sample_improvement.trim())
    ? input.sample_improvement.trim()
    : (di.adaptation_strategy != null ? String(di.adaptation_strategy).trim() : '');

return [{
  json: {
    style_id: styleId,
    status: 'COMPLETED',
    style_json: style,
    sample_gaps: sampleGaps || null,
    sample_improvement: sampleImprovement || null,
    workflow_id: body.workflow_id || 'flow_writing_style_extract',
    workflow_name: body.workflow_name || '提取创作风格',
    callback_url: body.callback_url || '',
    api_key: body.api_key || '',
  },
}];
